+
+        engine.register_bundle(bundle, "admin", 1000).unwrap();
+        let dash = engine.metrics_dashboard(2000);
+        let br = &dash.subsystem_metrics["bundle_registry"];
+        assert!(br.evaluations >= 1);
+    }
